diffs.replacement:
{
  "name": "iamhungry.com.pk",
  "description": "Premium Pakistani delivery-only restaurant serving Lahore's finest Biryani, Karahi, and traditional delights.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export type Category = 'Appetizers' | 'Main Courses' | 'Sides' | 'Desserts' | 'Beverages';

export interface MenuItem {
  id: string;
  name: string;
  description: string;
  price: number;
  category: Category;
  image: string;
  tags?: string[];
}

export interface CartItem extends MenuItem {
  quantity: number;
}

export interface UserDetails {
  name: string;
  phone: string;
  email: string;
  area: string;
  address: string;
}

export const LAHORE_AREAS = [
  "Gulberg", "DHA Phase 1-8", "Model Town", "Johar Town", "Garden Town", 
  "Bahria Town", "Wapda Town", "Valencia", "Iqbal Town", "Samnabad", 
  "Cavalry Ground", "Askari", "Paragon City", "Lake City"
];

import { GoogleGenAI, Type } from "@google/genai";
import { MENU_ITEMS } from './constants';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getFoodRecommendation = async (mood: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Based on the user's mood: "${mood}", suggest 2-3 items from this menu: ${JSON.stringify(MENU_ITEMS)}. 
      Return a friendly response explaining why these items match the mood. 
      Limit to 100 words. Keep it very appetizing and Pakistani culture-friendly.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm having trouble thinking of a recommendation right now, but our Chicken Biryani is always a hit in Lahore!";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShoppingBag, 
  Menu as MenuIcon, 
  X, 
  Plus, 
  Minus, 
  MapPin, 
  Phone, 
  Mail, 
  ChefHat, 
  Clock, 
  Truck,
  MessageCircle,
  ArrowRight
} from 'lucide-react';
import { MenuItem, CartItem, Category, UserDetails, LAHORE_AREAS } from './types';
import { MENU_ITEMS, RESTAURANT_INFO } from './constants';
import { getFoodRecommendation } from './geminiService';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | 'All'>('All');
  const [isAssistantOpen, setIsAssistantOpen] = useState(false);
  const [mood, setMood] = useState('');
  const [recommendation, setRecommendation] = useState('');
  const [isLoadingRec, setIsLoadingRec] = useState(false);

  // Checkout Form
  const [userDetails, setUserDetails] = useState<UserDetails>({
    name: '',
    phone: '',
    email: '',
    area: '',
    address: ''
  });
  const [orderComplete, setOrderComplete] = useState(false);

  const categories: (Category | 'All')[] = ['All', 'Appetizers', 'Main Courses', 'Sides', 'Desserts', 'Beverages'];

  const filteredMenu = useMemo(() => {
    return activeCategory === 'All' 
      ? MENU_ITEMS 
      : MENU_ITEMS.filter(item => item.category === activeCategory);
  }, [activeCategory]);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) {
        return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      }
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(i => i.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => {
      if (i.id === id) {
        const newQty = Math.max(0, i.quantity + delta);
        return { ...i, quantity: newQty };
      }
      return i;
    }).filter(i => i.quantity > 0));
  };

  const cartTotal = useMemo(() => cart.reduce((acc, item) => acc + (item.price * item.quantity), 0), [cart]);

  const handleRecommend = async () => {
    if (!mood) return;
    setIsLoadingRec(true);
    const rec = await getFoodRecommendation(mood);
    setRecommendation(rec || '');
    setIsLoadingRec(false);
  };

  const handleCheckout = (e: React.FormEvent) => {
    e.preventDefault();
    if (!LAHORE_AREAS.includes(userDetails.area)) {
      alert("We currently only deliver within Lahore. Please select a valid Lahore area.");
      return;
    }
    // Simulate API call
    setOrderComplete(true);
    setCart([]);
    setTimeout(() => {
      setOrderComplete(false);
      setIsCheckoutOpen(false);
      setIsCartOpen(false);
    }, 5000);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-stone-200">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center text-white">
              <ChefHat size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-emerald-900 leading-none">iamhungry<span className="text-emerald-600">.com.pk</span></h1>
              <p className="text-[10px] uppercase tracking-widest text-stone-500 font-semibold">Lahore's Online Kitchen</p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-8 text-sm font-medium text-stone-600">
            <a href="#menu" className="hover:text-emerald-600 transition-colors">Our Menu</a>
            <a href="#about" className="hover:text-emerald-600 transition-colors">About Us</a>
            <a href="#contact" className="hover:text-emerald-600 transition-colors">Contact</a>
          </div>

          <button 
            onClick={() => setIsCartOpen(true)}
            className="relative p-2 text-stone-700 hover:text-emerald-600 transition-colors"
          >
            <ShoppingBag size={24} />
            {cart.length > 0 && (
              <span className="absolute top-0 right-0 w-5 h-5 bg-emerald-600 text-white text-[10px] flex items-center justify-center rounded-full font-bold">
                {cart.reduce((a, b) => a + b.quantity, 0)}
              </span>
            )}
          </button>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative h-[85vh] flex items-center overflow-hidden bg-stone-900">
        <img 
          src="https://images.unsplash.com/photo-1588166524941-3bf61a9c41db?auto=format&fit=crop&w=1920&q=80" 
          className="absolute inset-0 w-full h-full object-cover opacity-50 scale-105"
          alt="Pakistani Cuisine"
        />
        <div className="absolute inset-0 bg-gradient-to-r from-stone-950 via-stone-900/40 to-transparent" />

        <div className="relative max-w-7xl mx-auto px-4 w-full">
          <div className="max-w-2xl">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-600/20 text-emerald-400 border border-emerald-500/30 text-xs font-bold uppercase tracking-wider mb-6">
              <MapPin size={14} /> Exclusively in Lahore
            </div>
            <h2 className="text-5xl md:text-7xl font-serif text-white mb-6 leading-[1.1]">
              Cravings <br /> 
              <span className="text-emerald-500 italic">Delivered</span> Fresh.
            </h2>
            <p className="text-lg text-stone-300 mb-10 leading-relaxed max-w-lg">
              Lahore's favorite online kitchen bringing authentic flavors of Biryani, Karahi, and Nihari straight to your doorstep. Hot, hygienic, and hungry!
            </p>
            <div className="flex flex-wrap gap-4">
              <a href="#menu" className="px-8 py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-bold rounded-xl transition-all flex items-center gap-2 group">
                Order Now <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
              </a>
              <button 
                onClick={() => setIsAssistantOpen(true)}
                className="px-8 py-4 bg-white/10 hover:bg-white/20 text-white border border-white/20 backdrop-blur-md font-bold rounded-xl transition-all"
              >
                Help Me Choose
              </button>
            </div>
          </div>
        </div>
      </section>

      {/* Features */}
      <section className="py-20 bg-white">
        <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-3 gap-12">
          <div className="flex flex-col items-center text-center group">
            <div className="w-16 h-16 bg-stone-100 rounded-2xl flex items-center justify-center text-emerald-600 mb-6 group-hover:bg-emerald-600 group-hover:text-white transition-all duration-300">
              <Clock size={32} />
            </div>
            <h3 className="text-xl font-bold mb-3">Fastest Delivery</h3>
            <p className="text-stone-500">We operate 24/7 in Lahore ensuring your food arrives steaming hot.</p>
          </div>
          <div className="flex flex-col items-center text-center group">
            <div className="w-16 h-16 bg-stone-100 rounded-2xl flex items-center justify-center text-emerald-600 mb-6 group-hover:bg-emerald-600 group-hover:text-white transition-all duration-300">
              <Truck size={32} />
            </div>
            <h3 className="text-xl font-bold mb-3">Online Only</h3>
            <p className="text-stone-500">A dedicated digital kitchen designed specifically for delivery logistics.</p>
          </div>
          <div className="flex flex-col items-center text-center group">
            <div className="w-16 h-16 bg-stone-100 rounded-2xl flex items-center justify-center text-emerald-600 mb-6 group-hover:bg-emerald-600 group-hover:text-white transition-all duration-300">
              <ChefHat size={32} />
            </div>
            <h3 className="text-xl font-bold mb-3">Chef Crafted</h3>
            <p className="text-stone-500">Every dish is prepared using traditional recipes and premium ingredients.</p>
          </div>
        </div>
      </section>

      {/* Menu Section */}
      <section id="menu" className="py-24 bg-stone-50">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-12">
            <div>
              <h2 className="text-4xl font-serif font-bold text-stone-900 mb-4">Explore Our Menu</h2>
              <p className="text-stone-500 max-w-md">Carefully packaged to retain heat and flavor during transit. Perfectly portioned for you and your loved ones.</p>
            </div>

            <div className="flex flex-wrap gap-2">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all ${
                    activeCategory === cat 
                      ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/20' 
                      : 'bg-white text-stone-600 hover:bg-stone-100 border border-stone-200'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredMenu.map(item => (
              <div key={item.id} className="bg-white rounded-2xl overflow-hidden border border-stone-100 group shadow-sm hover:shadow-xl transition-all duration-300">
                <div className="relative h-56 overflow-hidden">
                  <img 
                    src={item.image} 
                    alt={item.name}
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                  />
                  <div className="absolute top-4 right-4 px-3 py-1 bg-white/90 backdrop-blur shadow-sm rounded-lg font-bold text-emerald-700">
                    {item.price} PKR
                  </div>
                </div>
                <div className="p-6">
                  <span className="text-[10px] uppercase tracking-widest font-bold text-emerald-600 mb-2 block">{item.category}</span>
                  <h3 className="text-xl font-bold mb-2 group-hover:text-emerald-700 transition-colors">{item.name}</h3>
                  <p className="text-stone-500 text-sm mb-6 line-clamp-2 leading-relaxed">{item.description}</p>
                  <button 
                    onClick={() => addToCart(item)}
                    className="w-full py-3 bg-stone-900 hover:bg-emerald-600 text-white font-bold rounded-xl transition-all flex items-center justify-center gap-2"
                  >
                    <Plus size={18} /> Add to Order
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Cart Sidebar */}
      {isCartOpen && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-stone-900/40 backdrop-blur-sm" onClick={() => setIsCartOpen(false)} />
          <div className="relative w-full max-w-md bg-white h-full shadow-2xl flex flex-col animate-in slide-in-from-right duration-300">
            <div className="p-6 border-b flex items-center justify-between">
              <h2 className="text-2xl font-bold flex items-center gap-2">
                Your Order <span className="text-sm font-normal text-stone-400">({cart.reduce((a,b) => a+b.quantity, 0)} items)</span>
              </h2>
              <button onClick={() => setIsCartOpen(false)} className="p-2 hover:bg-stone-100 rounded-lg"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              {cart.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center text-center opacity-50">
                  <ShoppingBag size={64} className="mb-4 text-stone-200" />
                  <p className="text-lg font-medium">Your bag is empty</p>
                  <p className="text-sm">Let's add some delicious food!</p>
                </div>
              ) : (
                cart.map(item => (
                  <div key={item.id} className="flex gap-4">
                    <img src={item.image} className="w-20 h-20 object-cover rounded-lg" alt={item.name} />
                    <div className="flex-1">
                      <h4 className="font-bold">{item.name}</h4>
                      <p className="text-sm text-stone-500 mb-2">{item.price} PKR</p>
                      <div className="flex items-center gap-3">
                        <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:bg-stone-100 border rounded"><Minus size={14}/></button>
                        <span className="font-bold text-sm">{item.quantity}</span>
                        <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-stone-100 border rounded"><Plus size={14}/></button>
                      </div>
                    </div>
                    <button onClick={() => removeFromCart(item.id)} className="text-stone-400 hover:text-red-500"><X size={18}/></button>
                  </div>
                ))
              )}
            </div>

            {cart.length > 0 && (
              <div className="p-6 border-t bg-stone-50">
                <div className="flex justify-between items-center mb-4">
                  <span className="text-stone-500">Subtotal</span>
                  <span className="text-xl font-bold">{cartTotal} PKR</span>
                </div>
                <button 
                  onClick={() => setIsCheckoutOpen(true)}
                  className="w-full py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl shadow-lg shadow-emerald-600/20 transition-all"
                >
                  Proceed to Checkout
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Checkout Modal */}
      {isCheckoutOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-stone-900/60 backdrop-blur-md" onClick={() => !orderComplete && setIsCheckoutOpen(false)} />
          <div className="relative w-full max-w-2xl bg-white rounded-3xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center">
              <h3 className="text-3xl font-serif font-bold">Checkout</h3>
              <button onClick={() => setIsCheckoutOpen(false)} className="p-2 hover:bg-stone-100 rounded-full"><X /></button>
            </div>

            {orderComplete ? (
              <div className="p-12 text-center animate-in zoom-in duration-300">
                <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center mx-auto mb-6">
                  <ChefHat size={48} />
                </div>
                <h4 className="text-3xl font-bold mb-4 text-emerald-900">Order Received!</h4>
                <p className="text-stone-500 mb-8 leading-relaxed">
                  Thank you, <span className="font-bold text-stone-900">{userDetails.name}</span>. Our chefs are already preparing your feast. We will deliver to <span className="font-bold text-stone-900">{userDetails.area}</span> within 45 minutes.
                </p>
                <div className="p-4 bg-stone-100 rounded-xl text-sm font-medium text-stone-600">
                  Tracking ID: #IH-{Math.floor(Math.random() * 90000 + 10000)}
                </div>
              </div>
            ) : (
              <form onSubmit={handleCheckout} className="p-8 overflow-y-auto space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-stone-700">Full Name</label>
                    <input 
                      required 
                      type="text" 
                      className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-emerald-500 outline-none" 
                      placeholder="Asad Ahmed"
                      value={userDetails.name}
                      onChange={e => setUserDetails({...userDetails, name: e.target.value})}
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-stone-700">Phone Number</label>
                    <input 
                      required 
                      type="tel" 
                      className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-emerald-500 outline-none" 
                      placeholder="0300-1234567"
                      value={userDetails.phone}
                      onChange={e => setUserDetails({...userDetails, phone: e.target.value})}
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-bold text-stone-700">Lahore Area (We only deliver in Lahore)</label>
                  <select 
                    required 
                    className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-emerald-500 outline-none appearance-none"
                    value={userDetails.area}
                    onChange={e => setUserDetails({...userDetails, area: e.target.value})}
                  >
                    <option value="">Select your area...</option>
                    {LAHORE_AREAS.map(area => <option key={area} value={area}>{area}</option>)}
                    <option value="Outside Lahore">Outside Lahore (Not Supported)</option>
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-bold text-stone-700">Detailed Address</label>
                  <textarea 
                    required 
                    className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-emerald-500 outline-none h-32" 
                    placeholder="House #123, Street #5, Sector..."
                    value={userDetails.address}
                    onChange={e => setUserDetails({...userDetails, address: e.target.value})}
                  ></textarea>
                </div>

                <div className="p-6 bg-stone-50 rounded-2xl flex items-center justify-between">
                  <div>
                    <p className="text-stone-500 text-sm">Grand Total</p>
                    <p className="text-2xl font-bold text-stone-900">{cartTotal} PKR</p>
                  </div>
                  <button type="submit" className="px-10 py-4 bg-emerald-600 hover:bg-emerald-700 text-white font-bold rounded-xl transition-all">
                    Place Delivery Order
                  </button>
                </div>
              </form>
            )}
          </div>
        </div>
      )}

      {/* AI Assistant FAB */}
      <button 
        onClick={() => setIsAssistantOpen(true)}
        className="fixed bottom-8 left-8 w-16 h-16 bg-stone-900 hover:bg-emerald-600 text-white rounded-full shadow-2xl flex items-center justify-center transition-all z-40 group"
      >
        <MessageCircle size={32} className="group-hover:scale-110 transition-transform" />
      </button>

      {/* Assistant Modal */}
      {isAssistantOpen && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-stone-900/60 backdrop-blur-md" onClick={() => setIsAssistantOpen(false)} />
          <div className="relative w-full max-w-lg bg-white rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-200">
            <div className="bg-emerald-600 p-8 text-white relative">
              <button onClick={() => setIsAssistantOpen(false)} className="absolute top-6 right-6 p-2 hover:bg-emerald-500 rounded-full"><X /></button>
              <h4 className="text-2xl font-bold mb-2">Hungry Assistant</h4>
              <p className="opacity-80 text-sm">Tell me what you're feeling, and I'll suggest the perfect meal from our kitchen!</p>
            </div>
            <div className="p-8 space-y-6">
              <div className="space-y-3">
                <label className="text-sm font-bold text-stone-700">What's your mood today?</label>
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={mood}
                    onChange={e => setMood(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && handleRecommend()}
                    className="flex-1 px-4 py-3 rounded-xl border border-stone-200 outline-none focus:border-emerald-500"
                    placeholder="e.g., Cold weather, want something spicy!"
                  />
                  <button 
                    onClick={handleRecommend}
                    disabled={isLoadingRec || !mood}
                    className="p-3 bg-emerald-600 text-white rounded-xl disabled:opacity-50"
                  >
                    <ArrowRight />
                  </button>
                </div>
              </div>

              {isLoadingRec && (
                <div className="flex items-center gap-3 text-stone-500 animate-pulse py-4">
                  <div className="w-2 h-2 bg-emerald-600 rounded-full animate-bounce"></div>
                  <div className="w-2 h-2 bg-emerald-600 rounded-full animate-bounce delay-100"></div>
                  <div className="w-2 h-2 bg-emerald-600 rounded-full animate-bounce delay-200"></div>
                  <span>Thinking...</span>
                </div>
              )}

              {recommendation && !isLoadingRec && (
                <div className="bg-emerald-50 p-6 rounded-2xl border border-emerald-100 text-stone-800 leading-relaxed italic animate-in fade-in slide-in-from-bottom-4">
                  "{recommendation}"
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer id="contact" className="bg-stone-900 text-stone-300 py-24 mt-auto">
        <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-4 gap-16">
          <div className="col-span-1 md:col-span-2">
            <div className="flex items-center gap-2 mb-8">
              <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center text-white">
                <ChefHat size={24} />
              </div>
              <h1 className="text-2xl font-bold tracking-tight text-white">iamhungry<span className="text-emerald-600">.com.pk</span></h1>
            </div>
            <p className="text-stone-400 mb-8 max-w-sm leading-relaxed">
              Serving the authentic taste of Pakistan across Lahore. Operated exclusively online for maximum efficiency and food safety.
            </p>
            <div className="flex gap-4">
              <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center hover:bg-emerald-600 transition-colors cursor-pointer">
                <Phone size={18} />
              </div>
              <div className="w-10 h-10 rounded-full bg-white/5 border border-white/10 flex items-center justify-center hover:bg-emerald-600 transition-colors cursor-pointer">
                <Mail size={18} />
              </div>
            </div>
          </div>

          <div>
            <h4 className="text-white font-bold mb-6">Contact Us</h4>
            <ul className="space-y-4">
              <li className="flex items-center gap-3">
                <Phone size={18} className="text-emerald-500" />
                <span>{RESTAURANT_INFO.phone}</span>
              </li>
              <li className="flex items-center gap-3">
                <Mail size={18} className="text-emerald-500" />
                <span>{RESTAURANT_INFO.email}</span>
              </li>
              <li className="flex items-center gap-3">
                <MapPin size={18} className="text-emerald-500" />
                <span>Lahore, Pakistan</span>
              </li>
            </ul>
          </div>

          <div>
            <h4 className="text-white font-bold mb-6">Hours</h4>
            <ul className="space-y-2 opacity-80">
              <li>Open 24/7</li>
              <li>Delivery only</li>
              <li>Lahore Region</li>
            </ul>
          </div>
        </div>
        <div className="max-w-7xl mx-auto px-4 pt-16 mt-16 border-t border-white/5 text-center text-sm opacity-50">
          <p>© {new Date().getFullYear()} iamhungry.com.pk - All Rights Reserved.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'Appetizers' | 'Main Courses' | 'Sides' | 'Desserts' | 'Beverages';

export interface MenuItem {
  id: string;
  name: string;
  description: string;
  price: number;
  category: Category;
  image: string;
  tags?: string[];
}

export interface CartItem extends MenuItem {
  quantity: number;
}

export interface SavedAddress {
  id: string;
  label: string; // e.g., 'Home', 'Office'
  area: string;
  address: string;
}

export interface User {
  id: string;
  email: string;
  name: string;
  phone: string;
  savedAddresses: SavedAddress[];
}

export interface Order {
  id: string;
  userId: string;
  items: CartItem[];
  total: number;
  date: string;
  status: 'Pending' | 'Preparing' | 'Out for Delivery' | 'Delivered';
  deliveryAddress: string;
  deliveryArea: string;
}

export interface UserDetails {
  name: string;
  phone: string;
  email: string;
  area: string;
  address: string;
}

export const LAHORE_AREAS = [
  "Gulberg", "DHA Phase 1-8", "Model Town", "Johar Town", "Garden Town", 
  "Bahria Town", "Wapda Town", "Valencia", "Iqbal Town", "Samnabad", 
  "Cavalry Ground", "Askari", "Paragon City", "Lake City"
];

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShoppingBag, 
  Menu as MenuIcon, 
  X, 
  Plus, 
  Minus, 
  MapPin, 
  Phone, 
  Mail, 
  ChefHat, 
  Clock, 
  Truck,
  MessageCircle,
  ArrowRight,
  User as UserIcon,
  LogOut,
  History,
  Home,
  CheckCircle2
} from 'lucide-react';
import { MenuItem, CartItem, Category, UserDetails, LAHORE_AREAS, User, SavedAddress, Order } from './types';
import { MENU_ITEMS, RESTAURANT_INFO } from './constants';
import { getFoodRecommendation } from './geminiService';

const App: React.FC = () => {
  // --- Global State ---
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | 'All'>('All');

  // --- Auth & User State ---
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [isProfileOpen, setIsProfileOpen] = useState(false);

  // --- AI State ---
  const [isAssistantOpen, setIsAssistantOpen] = useState(false);
  const [mood, setMood] = useState('');
  const [recommendation, setRecommendation] = useState('');
  const [isLoadingRec, setIsLoadingRec] = useState(false);

  // --- Form States ---
  const [authForm, setAuthForm] = useState({ email: '', password: '', name: '', phone: '' });
  const [userDetails, setUserDetails] = useState<UserDetails>({
    name: '', phone: '', email: '', area: '', address: ''
  });
  const [orderComplete, setOrderComplete] = useState(false);
  const [orderHistory, setOrderHistory] = useState<Order[]>([]);

  // --- Persistence Simulation ---
  useEffect(() => {
    const savedUser = localStorage.getItem('ih_user');
    const savedOrders = localStorage.getItem('ih_orders');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedOrders) setOrderHistory(JSON.parse(savedOrders));
  }, []);

  useEffect(() => {
    if (currentUser) {
      setUserDetails(prev => ({
        ...prev,
        name: currentUser.name,
        email: currentUser.email,
        phone: currentUser.phone
      }));
    }
  }, [currentUser]);

  // --- Actions ---
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authMode === 'register') {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        email: authForm.email,
        name: authForm.name,
        phone: authForm.phone,
        savedAddresses: []
      };
      setCurrentUser(newUser);
      localStorage.setItem('ih_user', JSON.stringify(newUser));
    } else {
      // Simulate login
      const mockUser: User = {
        id: 'u1',
        email: authForm.email,
        name: 'Guest User',
        phone: '0300-1112233',
        savedAddresses: []
      };
      setCurrentUser(mockUser);
      localStorage.setItem('ih_user', JSON.stringify(mockUser));
    }
    setIsAuthModalOpen(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('ih_user');
    setIsProfileOpen(false);
  };

  const addAddress = (label: string, area: string, address: string) => {
    if (!currentUser) return;
    const newAddress: SavedAddress = { id: Date.now().toString(), label, area, address };
    const updatedUser = { ...currentUser, savedAddresses: [...currentUser.savedAddresses, newAddress] };
    setCurrentUser(updatedUser);
    localStorage.setItem('ih_user', JSON.stringify(updatedUser));
  };

  const selectAddress = (addr: SavedAddress) => {
    setUserDetails(prev => ({ ...prev, area: addr.area, address: addr.address }));
  };

  const filteredMenu = useMemo(() => {
    return activeCategory === 'All' 
      ? MENU_ITEMS 
      : MENU_ITEMS.filter(item => item.category === activeCategory);
  }, [activeCategory]);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => {
      if (i.id === id) {
        const newQty = Math.max(0, i.quantity + delta);
        return { ...i, quantity: newQty };
      }
      return i;
    }).filter(i => i.quantity > 0));
  };

  const cartTotal = useMemo(() => cart.reduce((acc, item) => acc + (item.price * item.quantity), 0), [cart]);

  const handleCheckout = (e: React.FormEvent) => {
    e.preventDefault();
    if (!LAHORE_AREAS.includes(userDetails.area)) {
      alert("We currently only deliver within Lahore. Please select a valid Lahore area.");
      return;
    }

    const newOrder: Order = {
      id: `IH-${Math.floor(Math.random() * 90000 + 10000)}`,
      userId: currentUser?.id || 'guest',
      items: [...cart],
      total: cartTotal,
      date: new Date().toISOString(),
      status: 'Preparing',
      deliveryAddress: userDetails.address,
      deliveryArea: userDetails.area
    };

    const updatedHistory = [newOrder, ...orderHistory];
    setOrderHistory(updatedHistory);
    localStorage.setItem('ih_orders', JSON.stringify(updatedHistory));

    setOrderComplete(true);
    setCart([]);
    setTimeout(() => {
      setOrderComplete(false);
      setIsCheckoutOpen(false);
      setIsCartOpen(false);
    }, 5000);
  };

  const handleRecommend = async () => {
    if (!mood) return;
    setIsLoadingRec(true);
    const rec = await getFoodRecommendation(mood);
    setRecommendation(rec || '');
    setIsLoadingRec(false);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-white/90 backdrop-blur-md border-b border-stone-200">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
            <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center text-white">
              <ChefHat size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-emerald-900 leading-none">iamhungry<span className="text-emerald-600">.com.pk</span></h1>
              <p className="text-[10px] uppercase tracking-widest text-stone-500 font-semibold">Lahore's Online Kitchen</p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-8 text-sm font-medium text-stone-600">
            <a href="#menu" className="hover:text-emerald-600 transition-colors">Our Menu</a>
            <a href="#about" className="hover:text-emerald-600 transition-colors">About</a>
            <a href="#contact" className="hover:text-emerald-600 transition-colors">Contact</a>
          </div>

          <div className="flex items-center gap-4">
            {currentUser ? (
              <button 
                onClick={() => setIsProfileOpen(true)}
                className="flex items-center gap-2 px-3 py-2 hover:bg-stone-100 rounded-xl transition-colors text-stone-700"
              >
                <div className="w-8 h-8 bg-emerald-100 text-emerald-700 rounded-full flex items-center justify-center font-bold text-xs uppercase">
                  {currentUser.name.charAt(0)}
                </div>
                <span className="hidden sm:inline text-sm font-semibold">{currentUser.name.split(' ')[0]}</span>
              </button>
            ) : (
              <button 
                onClick={() => { setIsAuthModalOpen(true); setAuthMode('login'); }}
                className="flex items-center gap-2 text-sm font-bold text-emerald-600 hover:text-emerald-700 transition-colors px-4 py-2 border border-emerald-100 rounded-xl"
              >
                <UserIcon size={18} /> Login
              </button>
            )}

            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-2 text-stone-700 hover:text-emerald-600 transition-colors"
            >
              <ShoppingBag size={24} />
              {cart.length > 0 && (
                <span className="absolute top-0 right-0 w-5 h-5 bg-emerald-600 text-white text-[10px] flex items-center justify-center rounded-full font-bold">
                  {cart.reduce((a, b) => a + b.quantity, 0)}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative h-[80vh] flex items-center overflow-hidden bg-stone-900">
        <img 
          src="https://images.unsplash.com/photo-1588166524941-3bf61a9c41db?auto=format&fit=crop&w=1920&q=80" 
          className="absolute inset-0 w-full h-full object-cover opacity-60"
          alt="Pakistani Cuisine"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-stone-950/80 via-transparent to-transparent" />

        <div className="relative max-w-7xl mx-auto px-4 w-full">
          <div className="max-w-2xl">
            <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-emerald-600/20 text-emerald-400 border border-emerald-500/30 text-xs font-bold uppercase tracking-wider mb-6">
              <MapPin size={14} /> Only In Lahore
            </div>
            <h2 className="text-6xl md:text-8xl font-serif text-white mb-6 leading-tight">
              Lahore's <br /> 
              <span className="text-emerald-400 italic">Favorite</span> Bites.
            </h2>
            <p className="text-lg text-stone-300 mb-10 leading-relaxed max-w-lg">
              The only delivery-focused kitchen bringing you the royal taste of Nihari and Biryani. Prepared with passion, delivered with speed.
            </p>
            <div className="flex flex-wrap gap-4">
              <a href="#menu" className="px-10 py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-bold rounded-2xl transition-all flex items-center gap-2 group shadow-xl shadow-emerald-900/40">
                Start Ordering <ArrowRight size={20} className="group-hover:translate-x-1 transition-transform" />
              </a>
              <button 
                onClick={() => setIsAssistantOpen(true)}
                className="px-8 py-4 bg-white/10 hover:bg-white/20 text-white border border-white/20 backdrop-blur-md font-bold rounded-2xl transition-all"
              >
                AI Recommendation
              </button>
            </div>
          </div>
        </div>
      </section>

      {/* Menu Section */}
      <section id="menu" className="py-24 bg-stone-50">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-12">
            <div>
              <h2 className="text-4xl font-serif font-bold text-stone-900 mb-4">Our Signature Menu</h2>
              <p className="text-stone-500 max-w-md italic">Every dish is vacuum-sealed and temperature-controlled for the best delivery experience.</p>
            </div>

            <div className="flex flex-wrap gap-2">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`px-5 py-2.5 rounded-xl text-sm font-bold transition-all ${
                    activeCategory === cat 
                      ? 'bg-emerald-600 text-white shadow-lg shadow-emerald-600/20' 
                      : 'bg-white text-stone-600 hover:bg-stone-100 border border-stone-200 shadow-sm'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
            {filteredMenu.map(item => (
              <div key={item.id} className="bg-white rounded-3xl overflow-hidden border border-stone-100 group shadow-sm hover:shadow-2xl transition-all duration-500">
                <div className="relative h-64 overflow-hidden">
                  <img 
                    src={item.image} 
                    alt={item.name}
                    className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
                  <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                    <span className="text-white font-serif text-xl font-bold">{item.price} PKR</span>
                  </div>
                </div>
                <div className="p-8">
                  <span className="text-[10px] uppercase tracking-[0.2em] font-black text-emerald-600 mb-3 block">{item.category}</span>
                  <h3 className="text-2xl font-bold mb-3 text-stone-900">{item.name}</h3>
                  <p className="text-stone-500 text-sm mb-8 leading-relaxed line-clamp-2">{item.description}</p>
                  <button 
                    onClick={() => addToCart(item)}
                    className="w-full py-4 bg-stone-900 hover:bg-emerald-600 text-white font-bold rounded-2xl transition-all flex items-center justify-center gap-2 group"
                  >
                    <Plus size={20} className="group-hover:rotate-90 transition-transform" /> Add To Bag
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Profile / Account Modal */}
      {isProfileOpen && currentUser && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-stone-900/60 backdrop-blur-md" onClick={() => setIsProfileOpen(false)} />
          <div className="relative w-full max-w-4xl bg-white rounded-[2rem] shadow-2xl overflow-hidden max-h-[85vh] flex flex-col md:flex-row">
            {/* Sidebar */}
            <div className="w-full md:w-64 bg-stone-50 p-8 border-r border-stone-100 flex flex-col">
              <div className="mb-8 text-center md:text-left">
                <div className="w-16 h-16 bg-emerald-600 text-white rounded-2xl flex items-center justify-center text-2xl font-bold mb-4 mx-auto md:mx-0">
                  {currentUser.name.charAt(0)}
                </div>
                <h4 className="text-xl font-bold text-stone-900">{currentUser.name}</h4>
                <p className="text-xs text-stone-500 mt-1">{currentUser.email}</p>
              </div>

              <div className="space-y-2 flex-1">
