                  <History size={18} /> Order History
                </button>
                <button className="w-full flex items-center gap-3 px-4 py-3 text-stone-500 hover:bg-white hover:text-emerald-600 font-bold rounded-xl transition-all">
                  <Home size={18} /> My Addresses
                </button>
              </div>

              <button 
                onClick={handleLogout}
                className="mt-8 flex items-center gap-3 px-4 py-3 text-red-500 hover:bg-red-50 font-bold rounded-xl transition-all"
