                        <div className="text-right">
                          <span className="text-[10px] font-black uppercase text-stone-400 block mb-1">Total</span>
                          <span className="font-bold text-stone-900">{order.total} PKR</span>
                        </div>
                      </div>
                      <div className="text-sm text-stone-600 space-y-1 mb-4">
                        <p className="flex items-center gap-2"><MapPin size={14}/> {order.deliveryArea}, {order.deliveryAddress}</p>
                        <p className="flex items-center gap-2"><Clock size={14}/> {new Date(order.date).toLocaleDateString()} at {new Date(order.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                      </div>
                      <div className="flex -space-x-2 overflow-hidden">
                        {order.items.map((item, i) => (
                          <img key={i} src={item.image} className="inline-block h-8 w-8 rounded-full ring-2 ring-white object-cover" alt={item.name} title={`${item.quantity}x ${item.name}`} />
