  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('ih_user');
    setIsProfileOpen(false);
  };

  const addAddress = (label: string, area: string, address: string) => {
    if (!currentUser) return;
    const newAddress: SavedAddress = { id: Date.now().toString(), label, area, address };
    const updatedUser = { ...currentUser, savedAddresses: [...currentUser.savedAddresses, newAddress] };
    setCurrentUser(updatedUser);
    localStorage.setItem('ih_user', JSON.stringify(updatedUser));
  };

  const selectAddress = (addr: SavedAddress) => {
    setUserDetails(prev => ({ ...prev, area: addr.area, address: addr.address }));
  };

  const filteredMenu = useMemo(() => {
    return activeCategory === 'All' 
      ? MENU_ITEMS 
      : MENU_ITEMS.filter(item => item.category === activeCategory);
  }, [activeCategory]);

  const addToCart = (item: MenuItem) => {
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => {
      if (i.id === id) {
        const newQty = Math.max(0, i.quantity + delta);
        return { ...i, quantity: newQty };
      }
      return i;
    }).filter(i => i.quantity > 0));
  };

  const cartTotal = useMemo(() => cart.reduce((acc, item) => acc + (item.price * item.quantity), 0), [cart]);

  const handleCheckout = (e: React.FormEvent) => {
    e.preventDefault();
    if (!LAHORE_AREAS.includes(userDetails.area)) {
      alert("We currently only deliver within Lahore. Please select a valid Lahore area.");
      return;
