              <li className="flex items-center gap-4 hover:text-emerald-400 transition-colors cursor-pointer">
                <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center"><Phone size={18} /></div>
                <span className="font-bold">{RESTAURANT_INFO.phone}</span>
              </li>
              <li className="flex items-center gap-4 hover:text-emerald-400 transition-colors cursor-pointer">
                <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center"><Mail size={18} /></div>
                <span className="font-bold break-all">{RESTAURANT_INFO.email}</span>
              </li>
            </ul>
          </div>

          <div>
            <h4 className="text-white font-black uppercase tracking-widest text-xs mb-8">Operations</h4>
            <ul className="space-y-4 font-bold">
              <li className="flex items-center gap-2 text-emerald-500"><Clock size={16}/> 24 / 7 Delivery</li>
              <li className="flex items-center gap-2"><MapPin size={16}/> Lahore City Wide</li>
              <li className="flex items-center gap-2 text-stone-500"><CheckCircle2 size={16}/> Hygiene Certified</li>
            </ul>
          </div>
        </div>
        <div className="max-w-7xl mx-auto px-4 pt-20 mt-20 border-t border-white/5 text-center text-sm opacity-40">
          <p>© {new Date().getFullYear()} iamhungry.com.pk - Crafted for the hungry souls of Lahore.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

export type Category = 'Appetizers' | 'Main Courses' | 'Sides' | 'Desserts' | 'Beverages';

export interface MenuItem {
  id: string;
  name: string;
  description: string;
  caption: string; // New field for catchy captions
  price: number;
  category: Category;
  image: string;
  tags?: string[];
}

export interface CartItem extends MenuItem {
  quantity: number;
}

export interface SavedAddress {
  id: string;
  label: string;
  area: string;
  address: string;
}

export interface User {
  id: string;
  email: string;
  name: string;
  phone: string;
  savedAddresses: SavedAddress[];
}

export interface Order {
  id: string;
  userId: string;
  items: CartItem[];
  total: number;
  date: string;
  status: 'Pending' | 'Preparing' | 'Out for Delivery' | 'Delivered';
  deliveryAddress: string;
  deliveryArea: string;
}

export interface UserDetails {
  name: string;
  phone: string;
  email: string;
  area: string;
  address: string;
}

export const LAHORE_AREAS = [
  "Gulberg", "DHA Phase 1-8", "Model Town", "Johar Town", "Garden Town", 
  "Bahria Town", "Wapda Town", "Valencia", "Iqbal Town", "Samnabad", 
  "Cavalry Ground", "Askari", "Paragon City", "Lake City"
];

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ShoppingBag, 
  Menu as MenuIcon, 
  X, 
  Plus, 
  Minus, 
  MapPin, 
  Phone, 
  Mail, 
  ChefHat, 
  Clock, 
  Truck,
  MessageCircle,
  ArrowRight,
  User as UserIcon,
  LogOut,
  History,
  Home,
  CheckCircle2,
  AlertCircle
} from 'lucide-react';
import { MenuItem, CartItem, Category, UserDetails, LAHORE_AREAS, User, SavedAddress, Order } from './types';
import { MENU_ITEMS, RESTAURANT_INFO } from './constants';
import { getFoodRecommendation } from './geminiService';

const categories: (Category | 'All')[] = ['All', 'Appetizers', 'Main Courses', 'Sides', 'Desserts', 'Beverages'];

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isCheckoutOpen, setIsCheckoutOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | 'All'>('All');
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isAssistantOpen, setIsAssistantOpen] = useState(false);
  const [mood, setMood] = useState('');
  const [recommendation, setRecommendation] = useState('');
  const [isLoadingRec, setIsLoadingRec] = useState(false);
  const [authForm, setAuthForm] = useState({ email: '', password: '', name: '', phone: '' });
  const [userDetails, setUserDetails] = useState<UserDetails>({
    name: '', phone: '', email: '', area: '', address: ''
  });
  const [orderComplete, setOrderComplete] = useState(false);
  const [orderHistory, setOrderHistory] = useState<Order[]>([]);

  // Operating Hours Logic (12 AM to 12 PM)
  const isKitchenOpen = useMemo(() => {
    const now = new Date();
    const hour = now.getHours();
    // 0 is 12 AM, 11 is 11 AM. 12 is Noon. 
    // Open from 0 (12 AM) to < 12 (Noon).
    return hour >= 0 && hour < 12;
  }, []);

  useEffect(() => {
    const savedUser = localStorage.getItem('ih_user');
    const savedOrders = localStorage.getItem('ih_orders');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
    if (savedOrders) setOrderHistory(JSON.parse(savedOrders));
  }, []);

  useEffect(() => {
    if (currentUser) {
      setUserDetails(prev => ({
        ...prev,
        name: currentUser.name,
        email: currentUser.email,
        phone: currentUser.phone
      }));
    }
  }, [currentUser]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (authMode === 'register') {
      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        email: authForm.email,
        name: authForm.name,
        phone: authForm.phone,
        savedAddresses: []
      };
      setCurrentUser(newUser);
      localStorage.setItem('ih_user', JSON.stringify(newUser));
    } else {
      const mockUser: User = {
        id: 'u1',
        email: authForm.email,
        name: 'Guest User',
        phone: '0300-1112233',
        savedAddresses: []
      };
      setCurrentUser(mockUser);
      localStorage.setItem('ih_user', JSON.stringify(mockUser));
    }
    setIsAuthModalOpen(false);
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('ih_user');
    setIsProfileOpen(false);
  };

  const selectAddress = (addr: SavedAddress) => {
    setUserDetails(prev => ({ ...prev, area: addr.area, address: addr.address }));
  };

  const filteredMenu = useMemo(() => {
    return activeCategory === 'All' 
      ? MENU_ITEMS 
      : MENU_ITEMS.filter(item => item.category === activeCategory);
  }, [activeCategory]);

  const addToCart = (item: MenuItem) => {
    if (!isKitchenOpen) {
      alert("Our kitchen is currently closed. We are open from 12:00 AM to 12:00 PM.");
      return;
    }
    setCart(prev => {
      const existing = prev.find(i => i.id === item.id);
      if (existing) return prev.map(i => i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { ...item, quantity: 1 }];
    });
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(i => {
      if (i.id === id) {
        const newQty = Math.max(0, i.quantity + delta);
        return { ...i, quantity: newQty };
      }
      return i;
    }).filter(i => i.quantity > 0));
  };

  const cartTotal = useMemo(() => cart.reduce((acc, item) => acc + (item.price * item.quantity), 0), [cart]);

  const handleCheckout = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isKitchenOpen) {
      alert("Kitchen is closed. Please come back between 12 AM and 12 PM.");
      return;
    }
    if (!LAHORE_AREAS.includes(userDetails.area)) {
      alert("We currently only deliver within Lahore. Please select a valid Lahore area.");
      return;
    }

    const newOrder: Order = {
      id: `IH-${Math.floor(Math.random() * 90000 + 10000)}`,
      userId: currentUser?.id || 'guest',
      items: [...cart],
      total: cartTotal,
      date: new Date().toISOString(),
      status: 'Preparing',
      deliveryAddress: userDetails.address,
      deliveryArea: userDetails.area
    };

    const updatedHistory = [newOrder, ...orderHistory];
    setOrderHistory(updatedHistory);
    localStorage.setItem('ih_orders', JSON.stringify(updatedHistory));

    setOrderComplete(true);
    setCart([]);
    setTimeout(() => {
      setOrderComplete(false);
      setIsCheckoutOpen(false);
      setIsCartOpen(false);
    }, 5000);
  };

  const handleRecommend = async () => {
    if (!mood) return;
    setIsLoadingRec(true);
    const rec = await getFoodRecommendation(mood);
    setRecommendation(rec || '');
    setIsLoadingRec(false);
  };

  const scrollToSection = (id: string) => {
    const el = document.getElementById(id);
    if (el) {
      const offset = 80;
      const bodyRect = document.body.getBoundingClientRect().top;
      const elementRect = el.getBoundingClientRect().top;
      const elementPosition = elementRect - bodyRect;
      const offsetPosition = elementPosition - offset;

      window.scrollTo({
        top: offsetPosition,
        behavior: 'smooth'
      });
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Operating Hours Alert */}
      {!isKitchenOpen && (
        <div className="bg-amber-600 text-white py-2 px-4 text-center font-bold text-sm flex items-center justify-center gap-2">
          <AlertCircle size={16} /> Kitchen is Closed. We operate 12:00 AM to 12:00 PM.
        </div>
      )}

      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-white/95 backdrop-blur-md border-b border-stone-200">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}>
            <div className="w-10 h-10 bg-emerald-600 rounded-lg flex items-center justify-center text-white">
              <ChefHat size={24} />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-emerald-900 leading-none">iamhungry<span className="text-emerald-600">.com.pk</span></h1>
              <p className="text-[10px] uppercase tracking-widest text-stone-500 font-semibold">Lahore's Online Kitchen</p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-8 text-sm font-bold text-stone-600">
            <button onClick={() => scrollToSection('menu')} className="hover:text-emerald-600 transition-colors uppercase tracking-widest text-[11px]">Our Menu</button>
            <button onClick={() => scrollToSection('about')} className="hover:text-emerald-600 transition-colors uppercase tracking-widest text-[11px]">About</button>
            <button onClick={() => scrollToSection('contact')} className="hover:text-emerald-600 transition-colors uppercase tracking-widest text-[11px]">Contact</button>
          </div>

          <div className="flex items-center gap-4">
            {currentUser ? (
              <button 
                onClick={() => setIsProfileOpen(true)}
                className="flex items-center gap-2 px-3 py-2 hover:bg-stone-100 rounded-xl transition-colors text-stone-700"
              >
                <div className="w-8 h-8 bg-emerald-100 text-emerald-700 rounded-full flex items-center justify-center font-bold text-xs uppercase">
                  {currentUser.name.charAt(0)}
                </div>
                <span className="hidden sm:inline text-sm font-semibold">{currentUser.name.split(' ')[0]}</span>
              </button>
            ) : (
              <button 
                onClick={() => { setIsAuthModalOpen(true); setAuthMode('login'); }}
                className="flex items-center gap-2 text-sm font-bold text-emerald-600 hover:text-emerald-700 transition-colors px-4 py-2 border border-emerald-100 rounded-xl"
              >
                <UserIcon size={18} /> Login
              </button>
            )}

            <button 
              onClick={() => setIsCartOpen(true)}
              className="relative p-2 text-stone-700 hover:text-emerald-600 transition-colors"
            >
              <ShoppingBag size={24} />
              {cart.length > 0 && (
                <span className="absolute top-0 right-0 w-5 h-5 bg-emerald-600 text-white text-[10px] flex items-center justify-center rounded-full font-bold">
                  {cart.reduce((a, b) => a + b.quantity, 0)}
                </span>
              )}
            </button>
          </div>
        </div>
      </nav>

      {/* Hero Section */}
      <section className="relative h-[80vh] flex items-center overflow-hidden bg-stone-900">
        <img 
          src="https://images.unsplash.com/photo-1588166524941-3bf61a9c41db?auto=format&fit=crop&w=1920&q=80" 
          className="absolute inset-0 w-full h-full object-cover opacity-60"
          alt="Pakistani Cuisine"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-stone-950/90 via-transparent to-transparent" />

        <div className="relative max-w-7xl mx-auto px-4 w-full text-center md:text-left">
          <div className="max-w-3xl">
            <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-emerald-600/30 text-emerald-300 border border-emerald-500/30 text-xs font-bold uppercase tracking-widest mb-8 animate-pulse">
              <Clock size={14} /> Open {RESTAURANT_INFO.hours}
            </div>
            <h2 className="text-6xl md:text-8xl font-serif text-white mb-8 leading-tight">
              Lahore's <br /> 
              <span className="text-emerald-400 italic">Finest</span> Flavors.
            </h2>
            <p className="text-xl text-stone-300 mb-12 leading-relaxed max-w-xl">
              Authentic, chef-crafted Pakistani cuisine delivered exclusively to your doorstep in Lahore. Every meal is a royal experience.
            </p>
            <div className="flex flex-wrap gap-4 justify-center md:justify-start">
              <button 
                onClick={() => scrollToSection('menu')}
                className="px-12 py-5 bg-emerald-600 hover:bg-emerald-500 text-white font-black rounded-2xl transition-all flex items-center gap-3 group shadow-2xl shadow-emerald-900/40 uppercase tracking-widest"
              >
                Start Ordering <ArrowRight size={20} className="group-hover:translate-x-1 transition-transform" />
              </button>
              <button 
                onClick={() => setIsAssistantOpen(true)}
                className="px-10 py-5 bg-white/10 hover:bg-white/20 text-white border border-white/20 backdrop-blur-md font-bold rounded-2xl transition-all uppercase tracking-widest text-sm"
              >
                AI Hunger Helper
              </button>
            </div>
          </div>
        </div>
      </section>

      {/* About Section */}
      <section id="about" className="py-24 bg-white relative overflow-hidden">
        <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
          <div className="relative">
            <img 
              src="https://images.unsplash.com/photo-1541518763669-27fef04b14ea?auto=format&fit=crop&w=1000&q=80" 
              className="rounded-[3rem] shadow-2xl relative z-10"
              alt="Our Kitchen"
            />
            <div className="absolute -bottom-10 -right-10 w-64 h-64 bg-emerald-100 rounded-full -z-0 opacity-50 blur-3xl"></div>
          </div>
          <div className="space-y-8">
            <span className="text-emerald-600 font-black uppercase tracking-[0.3em] text-xs">Our Story</span>
            <h2 className="text-5xl font-serif font-bold text-stone-900 leading-tight">Born in the Heart of Lahore.</h2>
            <p className="text-lg text-stone-600 leading-relaxed">
              iamhungry.com.pk is not just a restaurant; it's a movement to bring authentic Pakistani flavors into the digital age. Operated solely online, our kitchen focus remains on one thing: **Perfection in Delivery.**
            </p>
            <p className="text-lg text-stone-600 leading-relaxed">
              We understand the Lahori palate. From the spice levels of our Karahi to the aroma of our Biryani, every dish is prepared between 12 AM and 12 PM to serve the city's unique cravings with unmatched freshness.
            </p>
            <div className="grid grid-cols-2 gap-8 pt-4">
              <div className="border-l-4 border-emerald-600 pl-4">
                <p className="text-3xl font-bold">100%</p>
                <p className="text-sm text-stone-500 uppercase tracking-widest">Lahore Focused</p>
              </div>
              <div className="border-l-4 border-emerald-600 pl-4">
                <p className="text-3xl font-bold">Digital</p>
                <p className="text-sm text-stone-500 uppercase tracking-widest">First Kitchen</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Menu Section */}
      <section id="menu" className="py-24 bg-stone-50">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-16">
            <div className="space-y-4">
              <h2 className="text-5xl font-serif font-bold text-stone-900">The Royal Menu</h2>
              <p className="text-stone-500 max-w-md text-lg italic">Carefully curated dishes for the discerning Lahori foodie.</p>
            </div>

            <div className="flex flex-wrap gap-2">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`px-6 py-3 rounded-2xl text-sm font-bold transition-all ${
                    activeCategory === cat 
                      ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-600/30' 
                      : 'bg-white text-stone-600 hover:bg-stone-100 border border-stone-200 shadow-sm'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
            {filteredMenu.map(item => (
              <div key={item.id} className="bg-white rounded-[2.5rem] overflow-hidden border border-stone-100 group shadow-sm hover:shadow-2xl transition-all duration-500 flex flex-col">
                <div className="relative h-72 overflow-hidden">
                  <img 
                    src={item.image} 
                    alt={item.name}
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-60" />
                  <div className="absolute top-6 left-6 px-4 py-2 bg-white/90 backdrop-blur rounded-2xl shadow-sm">
                    <span className="font-bold text-emerald-700">{item.price} PKR</span>
                  </div>
                  <div className="absolute bottom-6 left-6 right-6">
                    <p className="text-emerald-400 font-bold italic text-lg drop-shadow-md">"{item.caption}"</p>
                  </div>
                </div>
                <div className="p-10 flex-1 flex flex-col">
                  <span className="text-[10px] uppercase tracking-[0.3em] font-black text-emerald-600 mb-4 block">{item.category}</span>
                  <h3 className="text-2xl font-bold mb-4 text-stone-900 group-hover:text-emerald-700 transition-colors">{item.name}</h3>
                  <p className="text-stone-500 text-sm mb-10 leading-relaxed flex-1 line-clamp-3">{item.description}</p>
                  <button 
                    onClick={() => addToCart(item)}
                    disabled={!isKitchenOpen}
                    className={`w-full py-5 font-bold rounded-[1.5rem] transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-xs ${
                      isKitchenOpen 
                        ? 'bg-stone-900 hover:bg-emerald-600 text-white shadow-lg' 
                        : 'bg-stone-200 text-stone-400 cursor-not-allowed'
                    }`}
                  >
                    <Plus size={18} /> {isKitchenOpen ? 'Add To Order' : 'Kitchen Closed'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Profile / Account Modal */}
      {isProfileOpen && currentUser && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-stone-900/60 backdrop-blur-md" onClick={() => setIsProfileOpen(false)} />
          <div className="relative w-full max-w-4xl bg-white rounded-[3rem] shadow-2xl overflow-hidden max-h-[85vh] flex flex-col md:flex-row animate-in zoom-in-95 duration-300">
            <div className="w-full md:w-72 bg-stone-50 p-10 border-r border-stone-100 flex flex-col">
              <div className="mb-10 text-center md:text-left">
                <div className="w-20 h-20 bg-emerald-600 text-white rounded-3xl flex items-center justify-center text-3xl font-bold mb-6 mx-auto md:mx-0 shadow-lg shadow-emerald-600/20">
                  {currentUser.name.charAt(0)}
                </div>
                <h4 className="text-2xl font-bold text-stone-900">{currentUser.name}</h4>
                <p className="text-sm text-stone-500 mt-1">{currentUser.email}</p>
              </div>

              <div className="space-y-2 flex-1">
                <button className="w-full flex items-center gap-3 px-5 py-4 bg-white shadow-sm text-emerald-600 font-bold rounded-2xl transition-all">
                  <History size={18} /> Order History
                </button>
                <button className="w-full flex items-center gap-3 px-5 py-4 text-stone-500 hover:bg-white hover:text-emerald-600 font-bold rounded-2xl transition-all">
                  <Home size={18} /> My Addresses
                </button>
              </div>

              <button 
                onClick={handleLogout}
                className="mt-10 flex items-center gap-3 px-5 py-4 text-red-500 hover:bg-red-50 font-bold rounded-2xl transition-all"
              >
                <LogOut size={18} /> Logout
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-12">
              <div className="flex items-center justify-between mb-10">
                <h3 className="text-4xl font-serif font-bold">Past Orders</h3>
                <button onClick={() => setIsProfileOpen(false)} className="p-3 hover:bg-stone-100 rounded-full transition-colors"><X /></button>
              </div>

              {orderHistory.filter(o => o.userId === currentUser.id).length === 0 ? (
                <div className="h-64 flex flex-col items-center justify-center text-stone-400 italic">
                  <History size={48} className="mb-4 opacity-20" />
                  No orders placed yet.
                </div>
              ) : (
                <div className="space-y-8">
                  {orderHistory.filter(o => o.userId === currentUser.id).map(order => (
                    <div key={order.id} className="p-8 border border-stone-100 rounded-[2rem] bg-stone-50/50 hover:border-emerald-200 transition-all">
                      <div className="flex flex-wrap items-center justify-between gap-6 mb-6">
                        <div>
                          <span className="text-[10px] font-black uppercase text-stone-400 block mb-1 tracking-widest">Order ID</span>
                          <span className="font-bold text-stone-900 text-lg">#{order.id}</span>
                        </div>
                        <div className="px-4 py-1.5 bg-emerald-100 text-emerald-700 rounded-xl text-xs font-bold flex items-center gap-2">
                          <CheckCircle2 size={14} /> {order.status}
                        </div>
                        <div className="text-right">
                          <span className="text-[10px] font-black uppercase text-stone-400 block mb-1 tracking-widest">Total Bill</span>
                          <span className="font-bold text-stone-900 text-lg">{order.total} PKR</span>
                        </div>
                      </div>
                      <div className="text-sm text-stone-600 space-y-2 mb-6 p-4 bg-white rounded-2xl border border-stone-100">
                        <p className="flex items-center gap-3"><MapPin size={14} className="text-emerald-600"/> {order.deliveryArea}, {order.deliveryAddress}</p>
                        <p className="flex items-center gap-3"><Clock size={14} className="text-emerald-600"/> {new Date(order.date).toLocaleDateString()} at {new Date(order.date).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</p>
                      </div>
                      <div className="flex -space-x-3 overflow-hidden">
                        {order.items.map((item, i) => (
                          <img key={i} src={item.image} className="inline-block h-10 w-10 rounded-full ring-4 ring-white object-cover shadow-sm" alt={item.name} title={`${item.quantity}x ${item.name}`} />
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Auth Modal (Login/Register) */}
      {isAuthModalOpen && (
        <div className="fixed inset-0 z-[80] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-stone-950/50 backdrop-blur-md" onClick={() => setIsAuthModalOpen(false)} />
          <div className="relative w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl overflow-hidden p-10 animate-in zoom-in-95 duration-300">
